import{c as e,Q as n,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Discrepancies","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/discrepancies.md","filePath":"guide/admin/discrepancies.md","lastUpdated":1778912818000}'),s={name:"guide/admin/discrepancies.md"};function r(i,t,d,l,c,h){return n(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="discrepancies" tabindex="-1">Discrepancies <a class="header-anchor" href="#discrepancies" aria-label="Permalink to &quot;Discrepancies&quot;">​</a></h1><p>The <strong>System → Discrepancies</strong> page is the triage inbox for tenant-level dangling data. The audit worker periodically scans every instance and surfaces records that exist in one data store but not the other:</p><ul><li><strong>Ghost</strong> — a PostgreSQL row with no MongoDB data.</li><li><strong>Orphan</strong> — MongoDB data with no PostgreSQL row.</li></ul><p>The ideal state is zero discrepancies. Anything in this inbox needs attention.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><ul><li>Header with title and a <strong>Run scan</strong> button (top right).</li><li>Toolbar with three filters and a <strong>Clear</strong> button.</li><li>Table with infinite scroll.</li></ul><h2 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Status</strong></td><td>Open / Resolved / Discarded / Auto-purged. Defaults to Open.</td></tr><tr><td><strong>Kind</strong></td><td>Ghost / Orphan. Optional.</td></tr><tr><td><strong>Instance</strong></td><td>Filter by instance. Optional.</td></tr><tr><td><strong>Clear</strong></td><td>Resets all filters to defaults.</td></tr><tr><td><strong>Run scan</strong></td><td>Triggers a new audit cycle immediately.</td></tr><tr><td>Count</td><td>&quot;N matching&quot;.</td></tr></tbody></table><h2 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Kind</strong></td><td>Ghost (danger) / Orphan (warning) badge.</td></tr><tr><td><strong>Instance</strong></td><td>Affected instance.</td></tr><tr><td><strong>Tenant name</strong></td><td>Tenant display name, when known.</td></tr><tr><td><strong>Tenant code</strong></td><td>Monospace identifier.</td></tr><tr><td><strong>First seen</strong></td><td>When the discrepancy was first detected.</td></tr><tr><td><strong>Last seen</strong></td><td>When the most recent scan still detected it.</td></tr><tr><td><strong>Status</strong></td><td>Open / Resolved / Discarded / Auto-purged.</td></tr><tr><td><strong>Evidence</strong></td><td>Link button with a teaser (&quot;3 coll · customer doc&quot; for orphans; &quot;last job&quot; for ghosts).</td></tr><tr><td><strong>Actions</strong></td><td>Trash (purge) and X (discard) for open rows; resolution note for closed rows.</td></tr></tbody></table><p>A row&#39;s background tints red if status is overdue.</p><h2 id="evidence-modal" tabindex="-1">Evidence modal <a class="header-anchor" href="#evidence-modal" aria-label="Permalink to &quot;Evidence modal&quot;">​</a></h2><p>Click the evidence link to see the audit signals that triggered the finding:</p><ul><li><strong>Orphans</strong> — matched MongoDB collections, whether the tenant ID had whitespace or case variants.</li><li><strong>Ghosts</strong> — PG tenant ID, creation date, last job timestamp.</li></ul><p>This is what you read before deciding to purge.</p><h2 id="actions-on-a-finding" tabindex="-1">Actions on a finding <a class="header-anchor" href="#actions-on-a-finding" aria-label="Permalink to &quot;Actions on a finding&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Purge</strong> (trash)</td><td>Deletes the dangling record. Ghost purges run inline. Orphan purges enqueue a job and offer a &quot;View job&quot; link to track on <a href="./migrations">Migrations</a>. Requires confirmation.</td></tr><tr><td><strong>Discard</strong> (X)</td><td>Marks the row as <code>discarded</code> and hides it from the inbox. <strong>Not permanent</strong> — the next audit scan re-detects and flips back to <code>open</code> if the dangle still exists. Discard means &quot;snooze until next audit cycle.&quot;</td></tr></tbody></table><p>There is no manual &quot;Resolve&quot; — that happens automatically when the next audit scan no longer detects the finding. The note <code>no longer detected</code> is recorded.</p><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>open ──┬──▶ resolved (purged or fixed elsewhere)</span></span>
<span class="line"><span>       ├──▶ discarded (snoozed; may flip back to open on next scan)</span></span>
<span class="line"><span>       └──▶ auto_purged (worker met strict criteria and acted without you)</span></span></code></pre></div><p>The auto-purge path is conservative — strict age and inactivity thresholds must be met. Most findings need a human in the loop.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Each dangle is keyed by <code>(instance, tenant code, kind)</code>. The same finding across scans is one row, not many.</li><li>Discard is for &quot;I&#39;ve looked at this and don&#39;t want to act yet.&quot; It is not &quot;ignore forever.&quot; If you genuinely never want to see it again, fix the root cause so the next scan finds nothing.</li><li>The page lists only <strong>tenant</strong> discrepancies. Future non-tenant finding domains (billing reconciliation, security audit, data integrity) get their own pages — they have different keying and different rules.</li></ul>`,23)])])}const p=e(s,[["render",r]]);export{u as __pageData,p as default};
